// 表格排版：表头黑体五号居中加粗，表格内容宋体五号靠左对齐
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var count = tables.Count;
var formattedTables = 0;

for (var i = 1; i <= count; i++) {
    var table = tables.Item(i);
    var rows = table.Rows;

    // 处理表头（第一行）
    if (rows.Count > 0) {
        var headerRow = rows.Item(1);
        var headerRange = headerRow.Range;
        headerRange.Font.NameFarEast = "黑体";
        headerRange.Font.Size = 10.5; // 五号
        headerRange.Font.Bold = true;
        headerRow.Cells.Item(1).Range.ParagraphFormat.Alignment = 1; // 居中

        // 确保表头所有单元格都居中
        var cells = headerRow.Cells;
        for (var j = 1; j <= cells.Count; j++) {
            cells.Item(j).Range.ParagraphFormat.Alignment = 1;
        }
    }

    // 处理表格内容（除第一行外的所有行）
    for (var k = 2; k <= rows.Count; k++) {
        var contentRow = rows.Item(k);
        var contentRange = contentRow.Range;
        contentRange.Font.NameFarEast = "宋体";
        contentRange.Font.Size = 10.5; // 五号
        contentRange.Font.Bold = false;

        // 确保内容行所有单元格都靠左对齐
        var contentCells = contentRow.Cells;
        for (var l = 1; l <= contentCells.Count; l++) {
            contentCells.Item(l).Range.ParagraphFormat.Alignment = 0; // 左对齐
        }
    }

    formattedTables++;
}

return {
    success: true,
    formattedTables: formattedTables,
    totalTables: count
};

// 表格排版：表头黑体五号居中加粗，表格内容宋体五号靠左对齐（分批处理）
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var totalCount = tables.Count;
var batchSize = 50;
var formattedCount = 0;

for (var start = 1; start <= totalCount; start += batchSize) {
    var end = Math.min(start + batchSize - 1, totalCount);

    for (var i = start; i <= end; i++) {
        var table = tables.Item(i);
        var rows = table.Rows;

        // 处理表头（第一行）
        if (rows.Count > 0) {
            var headerRow = rows.Item(1);
            var cells = headerRow.Cells;

            for (var j = 1; j <= cells.Count; j++) {
                var cellRange = cells.Item(j).Range;
                cellRange.Font.NameFarEast = "黑体";
                cellRange.Font.Size = 10.5;
                cellRange.Font.Bold = true;
                cellRange.ParagraphFormat.Alignment = 1;
            }
        }

        // 处理表格内容（除第一行外的所有行）
        for (var k = 2; k <= rows.Count; k++) {
            var contentRow = rows.Item(k);
            var contentCells = contentRow.Cells;

            for (var l = 1; l <= contentCells.Count; l++) {
                var cellRange = contentCells.Item(l).Range;
                cellRange.Font.NameFarEast = "宋体";
                cellRange.Font.Size = 10.5;
                cellRange.Font.Bold = false;
                cellRange.ParagraphFormat.Alignment = 0;
            }
        }

        formattedCount++;
    }
}

return {
    success: true,
    formattedTables: formattedCount,
    totalTables: totalCount
};
